224	    /// Drop weak entries whose weakly-tracked target is unreachable.
225	    ///
226	    /// Called from the post-mark hook (`Heap::full_collect_with_post_mark`)
227	    /// while the GC marker still holds the visited set. `is_reachable(id)`
228	    /// returns true iff the object at GC identity `id` was reached during
229	    /// the mark phase. Non-collectable LuaValue variants (`Int`, `Float`,
230	    /// `Bool`, `Nil`, `LightUserData`, primitive strings owned outside the
231	    /// heap) are treated as always reachable.
232	    ///
233	    /// Mode dispatch (`mode` is the `WEAK_KEYS | WEAK_VALUES` bitmask):
234	    ///   * `__mode = "v"`: clear when the value side is unreachable.
235	    ///   * `__mode = "kv"`: clear when either side is unreachable.
236	    ///   * `__mode = "k"`: clear when the key side is unreachable. NOTE:
237	    ///     this is a *simplification* of Lua's ephemeron semantics — full
238	    ///     ephemerons require a fixed-point iteration where a value's
239	    ///     reachability is conditional on the key's, and vice versa for
240	    ///     cycles. Here the trace impl marks values strongly regardless
241	    ///     of key reachability, so values held only by an entry that we
242	    ///     are about to clear survive one extra cycle. Sufficient for
243	    ///     `gc.lua`'s weak-table block; full ephemerons remain a follow-up.
244	    ///
245	    /// Tombstone semantics (value = Nil with the key slot still occupied)
246	    /// are preserved: a tombstone is NOT subject to weak-side checks
247	    /// because callers rely on the key remaining for `next(t, last_key)`.
248	    pub fn prune_weak_dead(&self, is_reachable: &dyn Fn(usize) -> bool) {
249	        let mode = self.weak_mode.get();
250	        if mode == 0 {
251	            return;
252	        }
253	        let weak_k = (mode & WEAK_KEYS) != 0;
254	        let weak_v = (mode & WEAK_VALUES) != 0;
255	        let mut entries = self.entries.borrow_mut();
256	        entries.retain(|(k, v)| {
257	            if matches!(v, LuaValue::Nil) {
258	                return true;
259	            }
260	            if weak_v && !value_is_reachable(v, is_reachable) {
261	                return false;
262	            }
263	            if weak_k && !value_is_reachable(k, is_reachable) {
264	                return false;
265	            }
266	            true
267	        });
268	    }
269	}
