2101	    /// macros.tsv: `luaC_checkGC → state.gc().check_step()`
2102	    ///
2103	    /// Phase D-2: drives implicit collection when the heap's byte threshold
2104	    /// is exceeded. Without this hook, loops that allocate without an
2105	    /// explicit `collectgarbage()` call (e.g. `closure.lua`'s
2106	    /// `while x[1] do local a = A..A end` GC-driven loop) never settle.
2107	    pub fn check_step(&self) {
2108	        self.collect_via_heap(/* force = */ false);
2109	    }
2110	
2111	    /// C: `luaC_fullgc(L, isemergency)` — full collection.
2112	    /// macros.tsv: `luaC_fullgc → state.gc().full_collect()`
2113	    pub fn full_collect(&self) {
2114	        self.collect_via_heap(/* force = */ true);
2115	    }
2116	
2117	    /// Shared driver behind both `full_collect` (force-collect) and
2118	    /// `check_step` (collect only if heap byte threshold exceeded).
2119	    ///
2120	    /// Snapshots the weak-tables registry, invokes the heap's collect path
2121	    /// with a post-mark weak-prune hook, and rebuilds the registry by
2122	    /// retaining only entries whose target was reachable. The same hook
2123	    /// works for both modes — the heap short-circuits when force=false and
2124	    /// the threshold isn't met.
2125	    fn collect_via_heap(&self, force: bool) {
2126	        let state_ref: &LuaState = &*self._state;
2127	
2128	        // Snapshot weak tables BEFORE the collect. `identity()` reads only
2129	        // the pointer address — safe even on still-dangling weak handles —
2130	        // and dedup by identity keeps the iteration linear.
2131	        let weak_tables_snapshot: Vec<lua_types::gc::GcRef<lua_types::value::LuaTable>> = {
2132	            let g = state_ref.global.borrow();
2133	            let mut seen = std::collections::HashSet::<usize>::new();
2134	            g.weak_tables_registry
2135	                .iter()
2136	                .filter_map(|w| w.upgrade())
2137	                .filter(|t| seen.insert(t.identity()))
2138	                .collect()
2139	        };
2140	
2141	        let alive_ids: std::cell::RefCell<std::collections::HashSet<usize>> =
2142	            std::cell::RefCell::new(std::collections::HashSet::new());
2143	        let collect_ran = std::cell::Cell::new(false);
2144	
2145	        {
2146	            let global = state_ref.global.borrow();
2147	            global.heap.unpause();
2148	            let roots = CollectRoots { global: &*global, thread: state_ref };
2149	            let hook = |is_reachable: &dyn Fn(usize) -> bool| {
2150	                collect_ran.set(true);
2151	                for t in &weak_tables_snapshot {
2152	                    let id = t.identity();
2153	                    if is_reachable(id) {
2154	                        t.prune_weak_dead(is_reachable);
2155	                        alive_ids.borrow_mut().insert(id);
2156	                    }
2157	                }
2158	            };
2159	            if force {
2160	                global.heap.full_collect_with_post_mark(&roots, hook);
2161	            } else {
2162	                global.heap.step_with_post_mark(&roots, hook);
2163	            }
2164	        }
2165	
2166	        if !collect_ran.get() {
2167	            return;
2168	        }
2169	
2170	        // After collect, drop weak-table-registry entries whose target was
2171	        // swept. Without this filter the registry leaks one dangling
2172	        // `GcWeak<LuaTable>` per dead weak table; the next collect would
2173	        // upgrade those handles (current placeholder GcWeak always returns
2174	        // Some) and the prune walk would deref freed memory.
2175	        let alive_set = alive_ids.into_inner();
2176	        let mut g = state_ref.global.borrow_mut();
2177	        g.weak_tables_registry
2178	            .retain(|w| alive_set.contains(&w.0.identity()));
2179	    }
