{
    let global = state_ref.global.borrow();
    global.heap.unpause();
    let roots = CollectRoots { global: &*global, thread: state_ref };
    let hook = |marker: &mut lua_gc::Marker| {
        collect_ran.set(true);
        // Ephemeron convergence: for each weak-key table that is
        // itself reachable, mark the value of every entry whose key
        // is already reachable. Drain after each pass and repeat
        // until the visited set stops growing. This implements the
        // "value's reachability is conditional on its key's
        // reachability" rule that defines ephemerons.
        loop {
            let visited_before = marker.visited_count();
            for t in &weak_tables_snapshot {
                let t_id = t.identity();
                if !marker.is_visited(t_id) {
                    continue;
                }
                let to_mark = t.ephemeron_values_to_mark(
                    &|id| marker.is_visited(id),
                );
                for v in &to_mark {
                    v.trace(marker);
                }
            }
            marker.drain_gray_queue();
            if marker.visited_count() == visited_before {
                break;
            }
        }
        // Prune entries whose weak target stayed unreachable.
        for t in &weak_tables_snapshot {
            let id = t.identity();
            if marker.is_visited(id) {
                t.prune_weak_dead(&|id| marker.is_visited(id));
                alive_ids.borrow_mut().insert(id);
            }
        }
    };
    if force {
        global.heap.full_collect_with_post_mark(&roots, hook);
    } else {
        global.heap.step_with_post_mark(&roots, hook);
    }
}

