    /// Ephemeron-convergence helper. For a `__mode = "k"` table, returns the
    /// list of values whose key is currently reachable per `is_reachable`.
    /// The caller marks each returned value via the GC marker — propagating
    /// reachability that depends on the key's reachability, which is the
    /// defining property of ephemerons. Returns an empty Vec for tables
    /// that are not weak-key.
    pub fn ephemeron_values_to_mark(&self, is_reachable: &dyn Fn(usize) -> bool) -> Vec<LuaValue> {
        let mode = self.weak_mode.get();
        if (mode & WEAK_KEYS) == 0 {
            return Vec::new();
        }
        let entries = self.entries.borrow();
        let mut out = Vec::new();
        for (k, v) in entries.iter() {
            if matches!(v, LuaValue::Nil) {
                continue;
            }
            if value_is_reachable(k, is_reachable) {
                out.push(v.clone());
            }
        }
        out
    }
}

